site medical services and supplies for any emergency"}], "monitoring": [{"id": "2.2.r3.p1", "label": "Presence of signages"}, {"id": "2.2.r3.p2", "label": "# of accidents"}, {"id": "2.2.r3.p3", "label": "Presence of scattered construction debris"}], "default_person_implement": null, "default_person_monitor": null, "default_timeframe": null}, {"id": "2.2.r4", "activity_id": "2.2", "activity": "2.2 Hazards and occupational health", "impacts": [{"id": "2.2.r4.i1", "label": "Misdemeanor at Construction stage"}, {"id": "2.2.r4.i2", "label": "Impacts associated with the contractor’s camp include:"}, {"id": "2.2.r4.i3", "label": "disposal of liquid and solid wastes."}, {"id": "2.2.r4.i4", "label": "theft, alcoholism and sexually transmitted diseases (especially HIV/AIDS)."}], "mitigations": [{"id": "2.2.r4.m1", "label": "Contractor to curb thefts and misbehaviour through a code of conduct."}, {"id": "2.2.r4.m2", "label": "Contractor to manage any of its waste properly."}], "monitoring": [{"id": "2.2.r4.p1", "label": "Number of locals engaged versus migrant labour from other areas."}, {"id": "2.2.r4.p2", "label": "Appropriate Site Management in place."}], "default_person_implement": null, "default_person_monitor": null, "default_timeframe": null}, {"id": "2.2.r5", "activity_id": "2.2", "activity": "2.2 Hazards and occupational health", "impacts": [{"id": "2.2.r5.i1", "label": "Occupational health hazards to workers during construction"}], "mitigations": [{"id": "2.2.r5.m1", "label": "Require all workers to strictly observe safety standards"}, {"id": "2.2.r5.m2", "label": "Provide potable water & sanitary facilities for construction workers"}], "monitoring": [{"id": "2.2.r5.p1", "label": "Quality of water source"}, {"id": "2.2.r5.p2", "label": "Presence of adequate sanitary facilities"}, {"id": "2.2.r5.p3", "label": "Number of medical complaints or cases"}], "default_person_implement": null, "default_person_monitor": null, "default_timeframe": null}, {"id": "2.2.r6", "activi